"""
mkt-christ layer — Acts chapters 20–21
Output: data/commentary/mkt-christ/acts.json
Run: python3 scripts/zc-christ-acts-20-21.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS_CH = {
"20": {
"1": "<p>Paul's departure from Ephesus — after the riot and three years of ministry — begins the journey toward Jerusalem that Acts has been building toward since 19:21. The journey pattern mirrors Jesus's own departure from Galilee toward Jerusalem (Luke 9:51 — 'he set his face to go to Jerusalem'). The Spirit-driven directionality of Paul's journey (20:22 — 'bound in the Spirit I am going to Jerusalem') echoes the divine necessity of Jesus's journey: 'the Son of Man must suffer many things' (Luke 9:22).</p>",
"2": "<p>The Macedonian revisit — encouraging the believers with 'much exhortation' (paraklēsei pollē) — is pastoral consolation in the pattern of Jesus's farewell discourses (John 14–17). The risen Lord's mission includes the sustained nurture of planted communities, not only initial proclamation. Paul's extended encouragement mirrors Jesus's extended private teaching of the Twelve before his passion journey: the teacher prepares his community for his absence.</p>",
"3": "<p>The Jewish plot against Paul at Corinth — triggering the return through Macedonia — begins the passion-pattern foreshadowing that will intensify through chapters 21–28. Jesus had forewarned: 'they will hand you over to councils and you will be beaten in synagogues' (Mark 13:9). The plot's detection and Paul's route change are providential protection — the same kind of divine intervention that enabled Jesus to move safely between Jerusalem and Galilee until 'his hour had come' (John 7:30; 8:20).</p>",
"4": "<p>The collection delegates — seven men from across the Gentile mission communities — accompanying Paul to Jerusalem represent the Gentile church's solidarity with the Jewish mother community. Jesus had said: 'by this all people will know that you are my disciples, if you have love for one another' (John 13:35). The collection is an act of love from those who have received the gospel through Israel toward those who first received and transmitted it — the body of Christ expressing its unity across ethnic and geographical lines.</p>",
"5": "<p>The resumption of 'we' at Philippi — after the gap since Acts 16:17 — reconnects Luke's eyewitness presence to the narrative at the point where Paul's Jerusalem journey intensifies. The 'we' sections of Acts (16:10–17; 20:5–21:18; 27:1–28:16) all cluster around maritime and Jerusalem journeys — the most vulnerable and significant phases of the mission. Luke's presence with Paul in these sections is his testimony to the events that shaped the early church's defining journey.</p>",
"6": "<p>The departure after the days of Unleavened Bread — the week of Passover — connects Paul's Jerusalem journey to the Passover season in which Jesus died. The timing is not coincidental in Luke's theology: Paul's passion journey to Jerusalem unfolds in the liturgical season of Israel's liberation, the season of Jesus's death and resurrection. The gospel's founding event and Paul's passion-journey shadow move in the same liturgical time.</p>",
"7": "<p>'On the first day of the week, when we were gathered together to break bread' — the first explicit attestation in Acts of Sunday (the day of resurrection) as the community's primary gathering day for the breaking of bread (the Eucharist). Jesus had appeared to the disciples on the first day (Luke 24:1; John 20:1, 19) and 'was known to them in the breaking of bread' (Luke 24:35). The community gathers on resurrection day to enact the resurrection meal — the risen Lord present in the breaking of bread that the disciples recognized at Emmaus.</p>",
"8": "<p>The many lamps in the upper room create the physical setting for the Eucharistic gathering — and the accident that follows. The upper room (hyperōon) is the same space as Jerusalem's upper room (Acts 1:13) where the disciples had gathered after the resurrection. The domestic, lamplight setting of the Eucharistic community in Troas echoes both the upper room of the Last Supper (Luke 22:12) and the resurrection appearances.</p>",
"9": "<p>Eutychus's fall from the window — 'sinking into deep sleep as Paul talked still longer' — and his apparent death creates the occasion for a death-and-resurrection miracle in the Eucharistic gathering. The young man falls during the proclamation of the word and during the breaking of bread — the two elements of the early Christian gathering (Acts 2:42: 'the apostles' teaching and the fellowship, to the breaking of bread'). His fall is the death that the gathering's theology addresses.</p>",
"10": "<p>Paul's 'falling on him and embracing him' deliberately echoes Elijah's action over the widow's son (1 Kgs 17:21) and Elisha's over the Shunammite's son (2 Kgs 4:34). The prophetic embodiment of resurrection — the living prophet lying on the dead body, transferring life — is the OT pattern that Paul enacts. But behind the OT pattern is the risen Christ who is the source of all resurrection power: Paul acts as agent of the Lord who is 'the resurrection and the life' (John 11:25).</p>",
"11": "<p>After the miracle, Paul 'broke bread and ate' — the Eucharistic meal proceeds after the resurrection sign. The sequence is theologically exact: death encountered (Eutychus falls), life restored (Paul's embrace), bread broken (the resurrection meal eaten). The Eucharist is the ritual enactment of what has just happened visibly: death is overcome, life is restored, and the community eats together in the presence of the risen Lord.</p>",
"12": "<p>The community 'took the youth away alive' and 'were not a little comforted' (pareклēthēsan) — the verb is parakaleo, the same root as the Paraclete (Helper) Jesus promised (John 14:16). The comfort the community receives after the death-and-resurrection miracle is the Spirit's ministry: the Comforter works through the enacted sign to strengthen the community's faith. The gathering that began with the breaking of bread and discourse ends with a living demonstration of resurrection.</p>",
"13": "<p>Paul walks from Troas to Assos (about 30 km on foot) while the ship takes the sea route. The deliberate separation — Paul alone on foot, companions by sea — creates a space of solitude before the final approach to Jerusalem, analogous to Jesus's withdrawal to pray before his passion (Luke 22:39–46). The one who walks to meet his suffering does so with deliberate solitude, not accidentally.</p>",
"14": "<p>The coastal voyage names — Assos, Mitylene, Chios, Samos, Miletus — are the geography of Paul's final approach to Jerusalem, each step bringing him closer to the city where suffering awaits. Jesus's journey to Jerusalem was similarly staged (Luke 9:51–19:44), with each stopping point a preparation for what lay ahead. Luke's attention to the precise itinerary mirrors his attention to Jesus's journey narrative in Luke 9–19.</p>",
"15": "<p>The deliberate route — bypassing Ephesus — is Paul's pastoral decision protecting the mission's momentum: a Jerusalem arrival for Pentecost over a pastoral detour in Ephesus. Jesus had also made deliberate routing decisions (avoiding certain regions, taking others) based on the mission's timing and his awareness of coming events. The risen Lord's servant navigates geography with theological purposefulness.</p>",
"16": "<p>The urgency to be in Jerusalem for Pentecost — fifty days after Passover — places Paul's Jerusalem arrival in the same liturgical season as the Spirit's original outpouring. If Paul arrives as planned, he will be in Jerusalem at Pentecost: the day when the Spirit first fell (Acts 2), the day Paul's collection arrives, the day his Jerusalem trials begin. The liturgical resonance is the risen Lord's own calendar at work in the mission.</p>",
"17": "<p>The summons of the Ephesian elders to Miletus begins Paul's most sustained and intimate pastoral speech in Acts. The word 'elders' (presbyterous) — those who shepherd the community — mirrors Jesus's commissioning of the Twelve as shepherds of Israel (Matt 10:6; Luke 22:26). Paul's farewell speech models what Jesus modeled in the upper room discourses (John 14–17): the departing leader preparing his community for his absence.</p>",
"18": "<p>'You yourselves know how I lived among you the whole time from the first day that I set foot in Asia.' Paul's appeal to community memory as the ground of his testimony echoes Jesus's appeal to his disciples: 'you are witnesses of these things' (Luke 24:48). The community's shared memory of the leader's life is the verification of his character — not external credentials but observed conduct. Paul's self-commendation through community memory mirrors Jesus's 'what have you seen and heard?' approach to testimony.</p>",
"19": "<p>'Serving the Lord with all humility and with tears and with trials through the plots of the Jews' — the combination of humility, tears, and suffering is the passion portrait of the Lord himself. Jesus had said: 'learn from me, for I am gentle and lowly in heart' (Matt 11:29); he wept over Jerusalem (Luke 19:41) and in Gethsemane. Paul's ministry form mirrors his Lord's: humble service, tears of pastoral investment, suffering through opposition.</p>",
"20": "<p>'I did not shrink from declaring to you anything that was profitable, and teaching you in public and from house to house' — the dual venue mirrors Jesus's own teaching pattern: synagogue (public) and house (private, Matt 13:36; Mark 7:17; Luke 10:38–42). The teacher who does not shrink from difficult truths follows Jesus's example: 'I have spoken openly to the world... I have said nothing in secret' (John 18:20). Faithful proclamation in all venues is the mark of the Lord's servant.</p>",
"21": "<p>'Testifying both to Jews and to Greeks of repentance toward God and of faith in our Lord Jesus Christ' — the bipartite gospel formula: repentance (metanoia) and faith in Jesus Christ. Jesus's own inaugural proclamation had been: 'Repent and believe in the gospel' (Mark 1:15); Luke's opening of Jesus's Galilean ministry was: 'The time is fulfilled, and the kingdom of God is at hand; repent and believe in the gospel.' Paul proclaims the same call the risen Lord first made, extended now to both Jews and Greeks.</p>",
"22": "<p>'And now, behold, I am going to Jerusalem, constrained by the Spirit, not knowing what will happen to me there.' The Spirit's constraint (dedemenos tō pneumati — bound in the Spirit) is the divine necessity language Jesus used of his own passion: 'must the Christ not suffer these things?' (Luke 24:26). Paul's Spirit-bound journey to Jerusalem under uncertain prospects mirrors Jesus's Spirit-led journey to Jerusalem under certain passion prediction. The risen Lord shapes his servant's journey in the pattern of his own.</p>",
"23": "<p>'Except that the Holy Spirit testifies to me in every city that imprisonment and afflictions await me' — the Spirit's forewarning of suffering in every city parallels Jesus's repeated passion predictions to his disciples (Luke 9:22; 9:44; 18:31–33). The prediction of suffering before entry into glory is the consistent pattern: 'Was it not necessary that the Christ should suffer these things and enter into his glory?' (Luke 24:26). Paul knows what awaits; he goes anyway — Gethsemane-like faithfulness.</p>",
"24": "<p>'But I do not account my life of any value to myself, if only I may finish my course and the ministry that I received from the Lord Jesus, to testify to the gospel of the grace of God.' Paul's self-giving mirrors Jesus's own self-emptying: 'the Son of Man came not to be served but to serve, and to give his life as a ransom for many' (Mark 10:45). The ministry received from the Lord Jesus is discharged in the Lord Jesus's own pattern: life held loosely, mission held firmly, grace proclaimed to the end.</p>",
"25": "<p>'And now, behold, I know that none of you among whom I have gone about proclaiming the kingdom will see my face again.' Paul's farewell prophecy of final departure echoes Jesus's farewell discourse prediction: 'A little while and you will see me no longer' (John 16:16). The departing Lord prepares his disciples for his absence while promising the Spirit's continued presence; Paul prepares the Ephesian elders for his absence while commending them to 'God and to the word of his grace' (v. 32). The pattern of departure, preparation, and continued presence through the word is the passion-resurrection pattern extended into apostolic ministry.</p>",
"26": "<p>'Therefore I testify to you this day that I am innocent of the blood of all, for I did not shrink from declaring to you the whole counsel of God.' Paul's innocence of blood echoes Ezekiel's watchman theology (Ezek 33:7–9) but also Jesus's own claim of faithfulness to the Father's word: 'I have not spoken on my own authority, but the Father who sent me has himself given me a commandment — what to say and what to speak' (John 12:49). The faithful proclaimer is innocent of the consequences of rejection.</p>",
"27": "<p>'The whole counsel of God' (pasan tēn boulēn tou theou) — the comprehensive divine plan that Paul has proclaimed without suppression. Jesus had declared: 'I have made known to you everything that I heard from my Father' (John 15:15). The servant who fully declares the master's word mirrors the Son who fully reveals the Father's will. Partial proclamation — suppressing difficult truths to avoid offense — fails both the Lord and the hearers.</p>",
"29": "<p>'I know that after my departure fierce wolves will come in among you, not sparing the flock' — the wolf-flock imagery invokes the Good Shepherd's warning: 'I am the good shepherd. The good shepherd lays down his life for the sheep. He who is a hired hand and not a shepherd... sees the wolf coming and leaves the sheep and flees, and the wolf snatches them' (John 10:11–12). Paul's warning that he is departing while wolves will come is the pastoral corollary: the undershepherds must do what the Good Shepherd modeled — guard the flock at the cost of their own comfort.</p>",
"30": "<p>'From among your own selves men will arise speaking twisted things, to draw away the disciples after them.' The internal false teacher as the greater threat echoes Jesus's warning about false prophets: 'Beware of false prophets, who come to you in sheep's clothing but inwardly are ravenous wolves' (Matt 7:15). The internal origin — 'from among your own selves' — makes the threat harder to detect and more damaging: the wolf in shepherd's clothing is harder to identify than the external predator.</p>",
"31": "<p>'Therefore be alert, remembering that for three years I did not cease night or day to admonish every one with tears.' The call to alertness (grēgoreite) echoes Jesus's Gethsemane command to the disciples: 'Watch and pray that you may not enter into temptation' (Matt 26:41). The disciples failed to watch at Gethsemane; the Ephesian elders must not repeat the failure. Paul's three years of tears-filled admonition models what the risen Lord requires of those who tend his flock: not casual oversight but intense, costly vigilance.</p>",
"32": "<p>'And now I commend you to God and to the word of his grace, which is able to build you up and to give you the inheritance among all those who are sanctified.' The commendation to God and the word echoes Jesus's high priestly prayer: 'I am no longer in the world, but they are in the world, and I am coming to you. Holy Father, keep them in your name' (John 17:11). The departing servant cannot keep the community; only the Father and his word can sustain them. Paul's commendation is the apostolic echo of Jesus's intercession.</p>",
"33": "<p>'I coveted no one's silver or gold or clothing.' The apostle's financial integrity in ministry mirrors Jesus's own non-acquisitive mission: 'Foxes have holes, and birds of the air have nests, but the Son of Man has nowhere to lay his head' (Matt 8:20). The servant is not above his master in economics: the one sent by the Lord who owned nothing accumulates nothing, trusting the Father who 'feeds the birds of the air' (Matt 6:26). The servant's integrity vindicates the Lord he represents.</p>",
"34": "<p>'These hands ministered to my necessities and to those who were with me.' Paul's manual labor — tent-making with Aquila and Priscilla — is the incarnational model of the servant who works within the human condition rather than above it. Jesus, the carpenter's son (Mark 6:3), worked with his hands before his public ministry; Paul continues to work with his hands throughout his ministry. The risen Lord's servant does not stand above the labor of human life.</p>",
"35": "<p>Paul cites a dominical saying — the word of the Lord Jesus that it is more blessed to give than to receive. This agraphon (unwritten saying, not in the canonical Gospels) grounds Paul's financial ethics in Jesus's own teaching. Jesus's earthly practice had modeled this: the giving of the kingdom (Luke 12:32), the giving of self (Mark 10:45), the commendation of the generous widow (Luke 21:1–4). The risen Lord's words — even those not recorded in the canonical Gospels — continue to govern his community's practice.</p>",
"36": "<p>Paul kneels and prays with the Ephesian elders — the posture of deepest supplication before departure. Jesus had knelt in Gethsemane: 'he withdrew from them about a stone's throw, and knelt down and prayed' (Luke 22:41). The departing servant kneels as his Lord knelt — surrendering the community he cannot keep to the Father who can. The Gethsemane posture in the Miletus farewell is Luke's deliberate echo: this too is a garden prayer before a passion journey.</p>",
"37": "<p>The communal weeping and embracing — 'they wept aloud and embraced Paul and kissed him' — echoes the farewell meals of the Last Supper context. The community's grief at the departing leader's loss mirrors the disciples' grief at Jesus's prediction of departure (John 16:6 — 'because I have said these things to you, sorrow has filled your hearts'). The pastoral love that has been formed over three years finds its expression in tears at the farewell — the same love Jesus had demonstrated and predicted would be the disciples' mark.</p>",
"38": "<p>'Being sorrowful especially because of the word he had spoken, that they would not see his face again.' The grief over finality mirrors the disciples' grief at Jesus's departure: 'You will weep and lament, but the world will rejoice' (John 16:20). The community that has experienced the risen Lord's presence through his servant grieves the servant's departure — not ultimate loss (they have the Spirit and the word) but the particular pastoral relationship that is irreplaceable. The escort to the ship is the farewell of those who know they will not meet again in this world."
},
"21": {
"1": "<p>The voyage from Miletus to Cos, Rhodes, and Patara is Paul's passage through the Aegean toward his Jerusalem destination — each stop a stage in the journey that mirrors Jesus's Galilean journey toward Jerusalem (Luke 9:51 — 'he set his face'). The geographical movement is inexorable: Paul, like his Lord, does not turn back from the city where suffering awaits. The coastal navigation is the physical expression of Spirit-driven resolve.</p>",
"2": "<p>The transfer to a Phoenician ship bound directly for Tyre — a larger vessel making the open-water crossing — accelerates the journey toward Jerusalem. The direct route chosen over the longer coastal alternative reflects Paul's urgency to reach Jerusalem for Pentecost (Acts 20:16). The Jerusalem destination pulls Paul forward with the same compulsion that the divine will pulled Jesus toward his passion: 'I must go on my way today and tomorrow and the day following, for it cannot be that a prophet should perish away from Jerusalem' (Luke 13:33).</p>",
"3": "<p>The week at Tyre with the Christian community there — an unplanned pastoral opportunity within the Jerusalem journey — mirrors Jesus's encounters along the road to Jerusalem (the ten lepers, Luke 17:11–19; Zacchaeus, Luke 19:1–10; Bartimaeus, Luke 18:35–43). The journey itself is a ministry: Paul does not suspend his pastoral engagement while traveling toward his appointed destination.</p>",
"4": "<p>'Through the Spirit they told Paul not to go on to Jerusalem' — the prophetic word spoken at Tyre. The community's Spirit-given warning of danger parallels the passion predictions Jesus received from his disciples (Peter's rebuke, Matt 16:22) and his own predictions (Luke 9:22, 44; 18:31–33). The community's loving prohibition — like Peter's 'Far be it from you, Lord! This shall never happen to you' — is not the Spirit's final word but the community's protective response to what the Spirit has revealed. Paul's resolution mirrors Jesus's response to Peter: the divine necessity supersedes human protective instinct.</p>",
"5": "<p>The farewell on the beach — kneeling to pray with the whole community including wives and children — is the second farewell scene of Paul's Jerusalem journey (after Miletus). The kneeling prayer echoes Gethsemane (Luke 22:41). The whole community on the beach, including children, creates the image of the full body of Christ gathered for prayer at the point of departure. The risen Lord's community sends its ambassador to Jerusalem with the same prayer posture Jesus used before his passion.</p>",
"6": "<p>The embarkation and return of the community to their homes — 'and they returned home' — closes the Tyre farewell with the community's return to ordinary life while Paul continues toward Jerusalem. Jesus's disciples too had their ordinary lives; the risen Lord's mission intersects with those ordinary lives at specific moments — farewell gatherings, prayer on beaches — and then releases them back to their daily patterns while the mission's advance continues.</p>",
"7": "<p>The one-day stop at Ptolemais — greeting the brothers there — maintains the missional pattern: even transit stops are pastoral occasions. Jesus had greeted people along his roads (Luke 19:5 — 'Zacchaeus, hurry and come down, for I must stay at your house today'). The risen Lord's ambassador creates community wherever he passes, not only where he plants.</p>",
"8": "<p>Philip the Evangelist's house in Caesarea — the last stop before Jerusalem. Philip, one of the Seven (Acts 6:5), who had evangelized Samaria (8:5), baptized the Ethiopian (8:38), and proclaimed the gospel along the coast (8:40), now hosts Paul. The convergence of two great figures of the early mission — Philip who opened the Samaritan and Ethiopian frontiers, Paul who opened the Gentile world — mirrors the convergence of redemptive history's streams. Philip is the 'evangelist' (euangelistou) — the herald of good news who has carried the gospel from Jerusalem to the ends of the earth.</p>",
"9": "<p>Philip's four prophesying daughters fulfill Joel 2:28 ('your daughters will prophesy'), cited at Pentecost (Acts 2:17). The ongoing fulfillment of the Pentecost prophecy in Philip's household — four women exercising prophetic gifts — demonstrates that the Spirit's Pentecostal outpouring was not a single event but an ongoing reality pervading the community across geography and gender. The risen Lord's Spirit, poured out at Pentecost, continues to fulfill Joel's promise in unexpected households.</p>",
"10": "<p>Agabus's arrival from Judea — the prophet who had predicted the Claudius famine (Acts 11:28) — brings the authoritative prophetic word to Paul at the last stop before Jerusalem. The prophet from Judea comes to Paul in Caesarea with a word about Jerusalem, just as OT prophets were sent from outside Jerusalem to address what was happening inside it (Amos from Tekoa to Bethel; Jeremiah from Anathoth to Jerusalem). The risen Lord's prophetic word reaches Paul through established channels of prophetic authority.</p>",
"11": "<p>Agabus binds his own hands and feet with Paul's belt — the OT symbolic action tradition (Isa 20:2–3; Jer 13:1–11; Ezek 4:1–8). The enacted prophecy makes visible what the Spirit is declaring: the man who owns this belt will be bound and delivered to the Gentiles in Jerusalem. The Spirit-through-prophet confirms what the Spirit-directly had been warning (20:23; 21:4): Jerusalem means chains. Jesus had said: 'they will seize you and persecute you, delivering you up to synagogues and prisons, and you will be brought before kings and governors for my name's sake' (Luke 21:12).</p>",
"12": "<p>The communal pleading — Paul's companions and the Caesarean community urging him not to go — mirrors Peter's rebuke of Jesus's passion prediction: 'Far be it from you, Lord! This shall never happen to you' (Matt 16:22). The loving community, confronted with their leader's certain suffering, responds with protective pleading. The pleading is not wrong in its love but insufficient as a response to divine necessity. The community's love cannot override the mission's requirement.</p>",
"13": "<p>'What are you doing, weeping and breaking my heart? For I am ready not only to be imprisoned but even to die in Jerusalem for the name of the Lord Jesus.' Paul's readiness for death — explicitly for the name of Jesus — is the Gethsemane resolution: 'Not my will but yours be done' (Luke 22:42). Jesus had gone to Jerusalem knowing what awaited (Luke 13:33: 'it cannot be that a prophet should perish away from Jerusalem'); Paul goes knowing what awaits (Acts 20:23; 21:11). Both choose the Father's will over personal safety.</p>",
"14": "<p>'The Lord's will be done' (tou kyriou to thelēma ginesthō) — the community's eventual acquiescence echoes the Lord's Prayer ('your will be done,' Matt 6:10) and Gethsemane (Luke 22:42 — 'not my will, but yours, be done'). The community that has pleaded against Paul's Jerusalem journey comes to rest in the same surrender Jesus modeled. The community's prayer posture is transformed from protective pleading to the Lord's-Prayer surrender — the appropriate response to divine will that transcends human preference.</p>",
"15": "<p>'After these days we got ready and went up to Jerusalem' — the ascent to Jerusalem (anabainein eis Hierosolyma) echoes Jesus's ascent to Jerusalem at the end of Luke's travel narrative (Luke 19:28 — 'he went on ahead, going up to Jerusalem'). The topographical term for Jerusalem — always 'up' because of its elevation — carries theological weight in Luke-Acts: the holy city is the destination of the redemptive journey, the place where suffering and vindication converge.</p>",
"16": "<p>Mnason of Cyprus — 'an early disciple' (archaiō mathētē) — provides hospitality at Jerusalem. The early disciple hosts the late apostle at the mission's center: Jerusalem remains the matrix out of which and toward which the mission moves. Jesus had arrived in Jerusalem to the hospitality of unnamed disciples who provided the upper room (Luke 22:10–12); Paul arrives to the hospitality of Mnason, a named disciple who provides what the Jerusalem journey requires.</p>",
"17": "<p>The Jerusalem community's welcome — 'the brothers received us gladly' — is the community's joy at the return of those who have been away in the mission. The prodigal son welcomed home (Luke 15:20 — 'his father saw him and felt compassion, and ran and embraced him and kissed him'); the returning missionaries received gladly. The community's joy at reunion is the kingdom's joy at restoration — the pattern of the father who ran to meet the returning child.</p>",
"18": "<p>The meeting with James and all the elders — the Jerusalem church's full leadership assembled — is the climactic reception of the collection and the report. The risen Lord's community in Jerusalem receives what its scattered members have sent: financial solidarity and missional report. James, the Lord's brother, presides — a trajectory from skeptical family member (John 7:5) to resurrection-convinced leader (1 Cor 15:7) to presiding bishop of the Jerusalem community. The resurrection has transformed even the most skeptical of intimate family members.</p>",
"19": "<p>Paul's report — 'one by one the things that God had done among the Gentiles through his ministry' — is the third major missional report in Acts (cf. 14:27; 15:4, 12). Each report makes God the subject: what God has done, not what Paul has accomplished. The consistent attributional pattern is the risen Lord's servant's proper self-understanding: he is the instrument, the Lord is the agent. The community glorifies God (v. 20) in response — the appropriate response to divine action reported through human witness.</p>",
"20": "<p>'You see, brother, how many thousands there are among the Jews who have believed. They are all zealous for the law.' The Jerusalem community's Jewish-Torah character — 'myriads' who have believed and who are Torah-zealous — represents the Jewish wing of the risen Lord's body. The community of the risen Messiah includes Torah-observant Jews and Torah-free Gentiles under the same Lord. The tension between these communities is not a failure of the mission but the complexity of what it means for the risen Lord to be Lord of all.</p>",
"21": "<p>The report that Paul teaches diaspora Jews to forsake Moses — false as a description of his actual teaching — threatens the Jerusalem community's acceptance of his mission. Jesus too was misrepresented by false witnesses who claimed he had said he would destroy the temple (Mark 14:58). The false report about Paul's teaching mirrors the false report about Jesus's — opponents distort the teaching they cannot defeat. The distortion is the mechanism of opposition: caricature what you cannot refute.</p>",
"22": "<p>The Jerusalem elders' proposed solution — Paul sponsoring Nazirite vows — is practical wisdom for navigating the cultural complexity of the mixed community. The risen Lord who had become 'all things to all people' through Paul (1 Cor 9:22) allows his servant to use cultural accommodation to preserve community. The vow sponsorship is not theological compromise but pastoral intelligence — keeping the community together by honoring its Jewish members' sensitivities without conceding the gospel's Gentile-inclusive ground.</p>",
"23": "<p>The four men with a Nazirite vow — whose vow completion Paul will sponsor — are Jewish believers exercising traditional Jewish piety within the community of the risen Lord. The risen Messiah's community includes those for whom Torah practice remains meaningful as cultural and devotional expression; the risen Lord does not strip his Jewish followers of their heritage but fulfills it. Paul's sponsorship of their vow is the act of the one who became 'as a Jew to Jews' (1 Cor 9:20) to win Jews.</p>",
"24": "<p>The elders' goal: 'all will know that there is nothing in what they have been told about you, but that you yourself also live in observance of the law.' The public demonstration of Paul's Jewish faithfulness is meant to silence the false report and preserve the community's unity. The risen Lord's body in Jerusalem requires the demonstration of continuity with Israel's heritage — not because the gospel requires Torah observance, but because the community's internal peace requires visible respect for the tradition its Jewish members embody.</p>",
"25": "<p>The elders restate the Jerusalem decree — confirming that the vow sponsorship does not change the terms for Gentile believers. The distinction between Jewish Christians (who may practice Torah) and Gentile Christians (who are not required to) remains the operative framework. The risen Lord is Lord of both without making both identical. The freedom of the gospel neither abolishes Jewish heritage nor imposes it on Gentiles; it liberates both in their own ways.</p>",
"26": "<p>Paul's compliance with the elders' proposal — taking the men the next day, purifying himself, entering the temple — is the act of pastoral flexibility that 1 Corinthians 9:20 describes: 'To the Jews I became as a Jew, in order to win Jews.' The compliance is not inconsistency with Paul's Galatians theology (circumcision is not required for salvation) but the application of his own principle of cultural accommodation in service of mission and community unity. The risen Lord's servant adapts his practice to serve the Lord's community.</p>",
"27": "<p>The Asian Jews who recognize Paul in the temple — and incite the riot — are the same Ephesian opponents who had opposed Paul's synagogue ministry (Acts 19:9). Their recognition of Trophimus (an Ephesian, Acts 20:4) and their false assumption that Paul brought him past the Gentile boundary triggers the crisis. The passion narrative pattern activates: false accusation from those with prior grievances, crowd excitement, violent seizure. The apostle enters his passion, as his Lord had entered his — in the holy city, during a festival, through false accusation.</p>",
"28": "<p>The double accusation — teaching against the people and the law and the holy place, and bringing a Gentile into the temple — mirrors the charge against Stephen (Acts 6:13–14) and behind that, the charge against Jesus (Mark 14:58). The false accusation about the temple is the recurring lie of the passion narrative: Jesus said he would destroy the temple; Stephen taught against this holy place; Paul brought a Gentile in. The lie adapts to each occasion but remains the same essential distortion of what the gospel says about the temple and God's presence.</p>",
"29": "<p>The false inference — seeing Trophimus in the city and assuming Paul brought him into the temple — is the mechanism of the lie. False witness at Jesus's trial was built on misremembered or distorted versions of real events (Mark 14:57–59). The crowd's assumption about Paul follows the same pattern: a real event (Trophimus was in the city with Paul) generates a false inference (therefore Paul took him into the temple). The passion's false testimony mechanism operates through the misreading of real facts.</p>",
"30": "<p>The city 'stirred up' (ekinēthē hē polis holē), the people 'running together,' Paul seized and dragged from the temple, the gates shut — the precise choreography of mob violence in a holy city at a festival. Jesus had been seized by a crowd in Gethsemane (Luke 22:47–53) at night during Passover; Paul is seized by a crowd in the temple courts during Pentecost. The passion geography — the holy city, a festival, a crowd, a sudden seizure — repeats with Paul as the protagonist.</p>",
"31": "<p>The Roman tribune's rapid response — soldiers and centurions descending from the Antonia fortress — is the providential protection that transforms Paul's mob beating into Roman custody. What looks like Roman interference is actually the risen Lord's preservation: the same God who sent an angel to release Peter (Acts 12:7) now uses Roman soldiers to rescue Paul from death. Divine providence works through both miraculous and political means to preserve the witness until his testimony is complete.</p>",
"32": "<p>The crowd stops beating Paul when the soldiers arrive — the mob's violence checked by imperial authority. Jesus had been protected from premature mob violence during his temple ministry (Luke 19:47–48: 'the chief priests and the scribes and the principal men of the people were seeking to destroy him, but they did not find anything they could do, for all the people were hanging on his words'). Divine preservation operates through the crowd's fear of Roman power, just as it operated through the crowd's desire to hear Jesus teach.</p>",
"33": "<p>The double chains — bound between two soldiers — begin Paul's extended Roman custody that will carry him to Rome (Acts 28). Jesus had been bound (John 18:12, 24) and handed from one authority to another (Annas → Caiaphas → Pilate → Herod → Pilate); Paul will be handed from tribune → Sanhedrin → Caesarea → Felix → Festus → Agrippa → Rome. The binding of the apostle begins the passion narrative's Roman-custody phase, which paradoxically becomes the vehicle for the gospel's advance to the empire's center.</p>",
"34": "<p>The tribune's inability to determine the charge from the crowd's contradictory shouting — the confusion of official process before the mob's noise — parallels Pilate's situation with the crowd at Jesus's trial (Luke 23:4, 13–25). Both Roman officials face a mob making competing and incomprehensible demands. The legal process is overwhelmed by the crowd's passion — the same dynamic that produced the injustice of Jesus's condemnation now produces the injustice of Paul's arrest on no clear charge.</p>",
"35": "<p>Paul carried by the soldiers up the stairs to protect him from the crowd — the physical protection of the apostle by the same power that will eventually judge him. The paradox is the passion paradox: the instruments of unjust power are the instruments of God's providential protection. Roman soldiers who will be Paul's guards and jailers are simultaneously the agents of his survival when the crowd would have killed him. Providence uses the ambiguous.</p>",
"36": "<p>'Away with him!' (aire auton) — the crowd's cry at Paul echoes the crowd's cry at Jesus's trial: 'Away with this man, and release to us Barabbas!' (Luke 23:18); 'Away with him, away with him, crucify him!' (John 19:15). The identical crowd-cry applied to both Jesus and Paul is Luke's most explicit passion-pattern marker in this chapter. Paul is not being compared to Jesus as equal — he is carrying in his body the pattern of rejection that his Lord established and promised his disciples would share: 'If they persecuted me, they will also persecute you' (John 15:20).</p>",
"37": "<p>Paul's Greek address to the tribune — 'May I say something to you?' — surprises the commander who had assumed Paul was the Egyptian agitator. Paul's Greek fluency (and subsequent Aramaic address to the crowd, v. 40) demonstrates his dual cultural competence: Greek enough to address a Roman officer, Aramaic-Hebrew enough to address a Jerusalem crowd. The risen Lord equips his servant with the exact cultural tools needed for the specific situation — the promise of words and wisdom before governors (Luke 21:15) in its multilingual embodiment.</p>",
"38": "<p>The tribune's misidentification — assuming Paul is the Egyptian who led the sicarii — is the comic-tragic irony of the passion narrative. The one who is actually bringing God's word to Israel is identified as its most dangerous enemy; the one who represents the risen Lord of Israel is assumed to be a revolutionary against Israel. The same misidentification characterizes Jesus's trial: the one who came to fulfill Israel's scriptures is tried as a blasphemer and subversive. The world consistently misidentifies the Lord's servants as the Lord was misidentified.</p>",
"39": "<p>'I am a Jew, from Tarsus in Cilicia, a citizen of no obscure city. I beg you, permit me to speak to the people.' Paul's self-identification — Jew from Tarsus — asserts both his Jewish identity and his Roman civic standing (Tarsus was a leading city) as the basis for his request. The risen Lord's servant uses every legitimate social resource available to advance the proclamation of the gospel. The permission to speak to the crowd that had been beating him is the risen Lord opening the door (1 Cor 16:9) that human hostility had seemed to close.</p>",
"40": "<p>Paul beckons and addresses the crowd in Aramaic — 'in the Hebrew dialect' — from the stairs of the Antonia fortress. The crowd that had been calling 'away with him' grows silent as their own language is heard. Language and cultural belonging create the opening for the gospel: the one they were trying to kill is one of them, speaking their language, addressing them as their own. The risen Lord who speaks in every language (Acts 2:6 — 'each one was hearing them speak in his own language') continues to reach people through their own cultural and linguistic world."
}
}

def main():
    existing = load_comm('mkt-christ', 'acts')
    merge_comm(existing, ACTS_CH)
    save_comm('mkt-christ', 'acts', existing)
    for ck in ['20', '21']:
        count = len(existing.get(ck, {}))
        print(f'Acts {ck}: {count} verses.')

if __name__ == '__main__':
    main()
